import scala.util.Random
import java.time.Instant
import java.util.concurrent.ConcurrentHashMap
import scala.jdk.CollectionConverters._

case class SessionToken(
  token: String,
  createdAt: Instant,
  expiresAt: Instant,
  userId: String
)

case class ApiKey(
  key: String,
  createdAt: Instant,
  userId: String,
  description: String
)

class TokenGenerationService(
  sessionExpirationMinutes: Int = 30,
  random: Random = new Random()
) {

  private val sessions = new ConcurrentHashMap[String, SessionToken]()
  private val apiKeys = new ConcurrentHashMap[String, ApiKey]()

  def generateSessionToken(userId: String): SessionToken = {
    val token = random.alphanumeric.take(32).mkString
    val now = Instant.now()
    val expiresAt = now.plusSeconds(sessionExpirationMinutes * 60L)
    
    val sessionToken = SessionToken(
      token = token,
      createdAt = now,
      expiresAt = expiresAt,
      userId = userId
    )
    
    sessions.put(token, sessionToken)
    sessionToken
  }

  def generateApiKey(userId: String, description: String = ""): ApiKey = {
    val key = random.alphanumeric.take(32).mkString
    val now = Instant.now()
    
    val apiKey = ApiKey(
      key = key,
      createdAt = now,
      userId = userId,
      description = description
    )
    
    apiKeys.put(key, apiKey)
    apiKey
  }

  def validateSessionToken(token: String): Option[SessionToken] = {
    Option(sessions.get(token)).filter { session =>
      Instant.now().isBefore(session.expiresAt)
    }
  }

  def validateApiKey(key: String): Option[ApiKey] = {
    Option(apiKeys.get(key))
  }

  def refreshSessionToken(token: String): Option[SessionToken] = {
    validateSessionToken(token).map { session =>
      val now = Instant.now()
      val expiresAt = now.plusSeconds(sessionExpirationMinutes * 60L)
      val refreshedSession = session.copy(expiresAt = expiresAt)
      sessions.put(token, refreshedSession)
      refreshedSession
    }
  }

  def invalidateSessionToken(token: String): Boolean = {
    sessions.remove(token) != null
  }

  def revokeApiKey(key: String): Boolean = {
    apiKeys.remove(key) != null
  }

  def cleanupExpiredSessions(): Int = {
    val now = Instant.now()
    val expiredTokens = sessions.asScala.filter { case (_, session) =>
      now.isAfter(session.expiresAt)
    }.keys.toSeq
    
    expiredTokens.foreach(sessions.remove)
    expiredTokens.size
  }

  def getActiveSessions(userId: String): List[SessionToken] = {
    val now = Instant.now()
    sessions.asScala.values
      .filter(session => session.userId == userId && now.isBefore(session.expiresAt))
      .toList
  }

  def getUserApiKeys(userId: String): List[ApiKey] = {
    apiKeys.asScala.values
      .filter(_.userId == userId)
      .toList
  }

  def invalidateAllUserSessions(userId: String): Int = {
    val userTokens = sessions.asScala.filter { case (_, session) =>
      session.userId == userId
    }.keys.toSeq
    
    userTokens.foreach(sessions.remove)
    userTokens.size
  }

  def revokeAllUserApiKeys(userId: String): Int = {
    val userKeys = apiKeys.asScala.filter { case (_, apiKey) =>
      apiKey.userId == userId
    }.keys.toSeq
    
    userKeys.foreach(apiKeys.remove)
    userKeys.size
  }

  def getSessionCount: Int = sessions.size()

  def getApiKeyCount: Int = apiKeys.size()
}

object TokenGenerationService {
  def apply(sessionExpirationMinutes: Int = 30): TokenGenerationService = {
    new TokenGenerationService(sessionExpirationMinutes)
  }
}

class SecureTokenGenerator(random: Random = new Random()) {
  
  def generateToken(length: Int = 32): String = {
    random.alphanumeric.take(length).mkString
  }

  def generateHexToken(length: Int = 32): String = {
    random.alphanumeric.filter(_.isDigit).take(length).mkString
  }

  def generateNumericToken(length: Int = 6): String = {
    (1 to length).map(_ => random.nextInt(10)).mkString
  }

  def generateAlphaToken(length: Int = 32): String = {
    random.alphanumeric.filter(_.isLetter).take(length).mkString
  }

  def generateCustomToken(charset: String, length: Int): String = {
    (1 to length).map(_ => charset(random.nextInt(charset.length))).mkString
  }
}

object SecureTokenGenerator {
  def apply(): SecureTokenGenerator = new SecureTokenGenerator()
}